#include <bits/stdc++.h>
using namespace std;
const int mod=1e4+7;
long long n,m,num[100005],col[100005];
long long sum[100005][4][2];
long long ans=0;
int main(){
    scanf("%lld%lld",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%lld",&num[i]);
    for(int i=1;i<=n;i++)
        scanf("%lld",&col[i]);
    for(int i=1;i<=n;i++){
        if(sum[col[i]][0][i%2]){
            ans+=1LL*(i%mod)*(num[i]%mod)*(sum[col[i]][0][i%2]%mod)%mod;
            ans%=mod;
            ans+=sum[col[i]][1][i%2];
            ans%=mod;
            ans+=sum[col[i]][2][i%2]*(num[i]%mod)%mod;
            ans%=mod;
            ans+=sum[col[i]][3][i%2]*(i%mod)%mod;
            ans%=mod;
        }
        sum[col[i]][0][i%2]++;
        sum[col[i]][1][i%2]+=i*num[i],sum[col[i]][1][i%2]%=mod;
        sum[col[i]][2][i%2]+=i,sum[col[i]][2][i%2]%=mod;
        sum[col[i]][3][i%2]+=num[i],sum[col[i]][3][i%2]%=mod;
    }
    printf("%lld",ans);
    return 0;
}
